section.code:
{
  "$id": "inverted-header-content-first/blog-post",
  "type": "object",
  "required": ["body", "title", "slug", "tags"],
  "additionalProperties": false,
  "properties": {
    "body":  {"type": "string", "minLength": 200, "description": "600-800 word article in markdown."},
    "title": {"type": "string", "minLength": 4, "maxLength": 90, "description": "Sharp 6-10 word title summarising `body`."},
    "slug":  {"type": "string", "pattern": "^[a-z0-9-]{1,80}$", "description": "kebab-case slug derived from `title`."},
    "tags":  {"type": "array", "items": {"type": "string"}, "minItems": 3, "maxItems": 5, "description": "3-5 lowercase tags from `body` topics."}
  }
}

example.code:
{
  "body": "[600-800 words of markdown article content...]",
  "title": "Inverted Header Improves Structured-Output Quality",
  "slug": "inverted-header-improves-structured-output-quality",
  "tags": ["structured-output", "schema-design", "pydantic"]
}

{
  "title": "Some Topic",
  "slug": "some-topic",
  "body": "[body must now rationalise the blind title above...]"
}
